app.use(express.json({ limit: '10kb' }));            // cap body size
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic abuse protection
```

### 2. Validate input (even on GET routes that will grow)
Use a schema validator like `zod` or `joi` rather than ad-hoc checks. For example, if `/users` gains query params:
```js
const { z } = require('zod');
const listUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
  offset: z.coerce.number().int().min(0).default(0),
});

app.get('/users', (req, res, next) => {
  const parsed = listUsersQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid query' });
  // ... use parsed.data
});
```
Never interpolate `req.query`/`req.params`/`req.body` into DB queries, shell commands, file paths, or HTML.

### 3. Centralized error handling
Avoid leaking stack traces or internal messages to clients:
```js
// 404 handler
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// Error handler — MUST have 4 args
app.use((err, req, res, next) => {
  console.error(err); // log server-side only
  const status = err.status || 500;
  res.status(status).json({
    error: status < 500 ? err.message : 'Internal server error',
  });
});
```

### 4. Wrap async handlers
Unhandled promise rejections silently hang requests. Use a helper:
```js
const asyncHandler = (fn) => (req, res, next) =>
  Promise.resolve(fn(req, res, next)).catch(next);
```

### 5. Don't leak framework fingerprint & PII
- `app.disable('x-powered-by');` (helmet does this too).
- Consider whether `/users` should expose email addresses without auth — emails are PII. Require authentication/authorization, and return only the fields the caller needs.

### 6. Harden the listener & process
```js
