const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { param, query, validationResult } = require('express-validator');

const app = express();

// --- Security middleware ---
app.disable('x-powered-by');                    // Hide Express fingerprint
app.use(helmet());                              // Sensible security headers
app.use(express.json({ limit: '10kb' }));       // Cap body size (DoS)
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Rate limiting ---
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Validation helper ---
const validate = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ error: 'Invalid input' }); // don't echo user input
  }
  next();
};

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get(
  '/users',
  [
    query('limit').optional().isInt({ min: 1, max: 100 }).toInt(),
    query('offset').optional().isInt({ min: 0 }).toInt(),
  ],
  validate,
  (req, res, next) => {
    try {
      // TODO: require authentication before exposing PII
      const users = [
        { id: 1, name: 'Alice' },   // email removed unless caller is authorized
        { id: 2, name: 'Bob' },
      ];
      res.json(users);
    } catch (err) {
      next(err);
    }
  }
);

// --- 404 handler ---
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// --- Centralized error handler (never leak stack traces) ---
app.use((err, req, res, _next) => {
  console.error({ msg: err.message, stack: err.stack, path: req.path });
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

// --- Graceful startup / shutdown ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

server.on('error', (err) => {
  console.error('Server error:', err);
  process.exit(1);
});

const shutdown = (signal) => {
  console.log(`${signal} received, shutting down`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref(); // force exit after 10s
};
process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  shutdown('uncaughtException');
});

module.exports = app;
